/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    const n = nums.length;

    // The maximum number of special indices achievable is floor((n - 2) / 2) + 1 if n >= 3 and we consider boundary effects carefully,
    // or more simply, the maximum number of peaks we can create.
    // A sequence of peaks looks like: Valley, Peak, Valley, Peak, ...
    // The number of possible indices for peaks is n - 2 (from index 1 to n-2).
    // Peaks must be separated by at least one non-peak element.
    // The maximum number of peaks is roughly ceil((n-2) / 2).
    // For n=3, indices {1}. Max peaks = 1.
    // For n=4, indices {1, 2}. Max peaks = 1. (e.g., [a, b, c, d], if b is peak, c cannot be peak relative to b).
    // For n=5, indices {1, 2, 3}. Max peaks = 2. (e.g., [a, b, c, d, e] -> b peak, d peak).
    // Max peaks = Math.ceil((n - 2) / 2) if we can always achieve this.
    // Let k be the number of special indices. These indices i_1, i_2, ..., i_k must satisfy:
    // 1 <= i_1 < i_2 < ... < i_k <= n - 2
    // i_{j+1} - i_j >= 2 (to ensure separation)
    // Maximum k is achieved when i_{j+1} = i_j + 2.
    // If i_1 = 1, i_k = 1 + 2(k-1). We need 1 + 2(k-1) <= n - 2
    // 2k - 1 <= n - 2
    // 2k <= n - 1
    // k <= (n - 1) / 2
    // Maximum k = Math.floor((n - 1) / 2).
    // Let's check the examples:
    // n=3: max k = floor(2/2) = 1. (Example 1: 1)
    // n=4: max k = floor(3/2) = 1. (Example 2: 1)
    // n=5: max k = floor(4/2) = 2. (Example 3: 2)
    // This seems to be the maximum number of special indices achievable.

    const maxSpecialIndices = Math.floor((n - 1) / 2);

    if (maxSpecialIndices === 0) {
        return 0;
    }

    // We need to select maxSpecialIndices positions i_1, i_2, ..., i_k
    // such that i_{j+1} >= i_j + 2, and the cost to make them peaks is minimized.
    // A peak at index i requires:
    // nums[i] > nums[i-1] AND nums[i] > nums[i+1]
    // To minimize cost, we should aim for the smallest possible peak value that satisfies the conditions.
    // If we choose a set of indices $I = \{i_1, \dots, i_k\}$ such that $|i_{j+1} - i_j| \ge 2$,
    // then the neighbors of any $i_j$ are not $i_m$ for $m \ne j$.
    // For a fixed set $I$, the cost is minimized when, for each $i \in I$,
    // $nums'[i] = \max(nums[i], nums[i-1] + 1, nums[i+1] + 1)$.
    // The cost for $i$ is $\max(0, nums[i-1] + 1 - nums[i], nums[i+1] + 1 - nums[i])$.

    // Since we want to minimize total cost, and the choices are coupled (changing nums[i] affects neighbors),
    // a greedy approach on the indices seems appropriate, prioritizing the indices that require less initial modification.

    // Let's fix the set of indices to be $I = \{1, 3, 5, \dots, 2k - 1\}$, where $k = \text{maxSpecialIndices}$.
    // This set is always valid regarding separation.
    const k = maxSpecialIndices;
    const indicesToMakePeak = [];
    for (let j = 0; j < k; j++) {
        indicesToMakePeak.push(2 * j + 1);
    }

    let currentNums = [...nums];
    let totalCost = 0;

    // Iterate through the chosen peak indices in increasing order.
    for (const i of indicesToMakePeak) {
        // Target value for nums'[i] must be strictly greater than its current neighbors.
        const requiredMin = Math.max(currentNums[i - 1] + 1, currentNums[i + 1] + 1);

        // The cost is incurred only if currentNums[i] is less than the required minimum.
        const cost = Math.max(0, requiredMin - currentNums[i]);

        totalCost += cost;

        // Update the array for subsequent calculations.
        currentNums[i] += cost;
    }

    // Because the selected indices are separated by at least 1 index, and the neighbors of i are i-1 and i+1,
    // if i and j are in indicesToMakePeak, then |i - j| >= 2.
    // If i = 2j+1 and j = 2m+1, then |i-j| >= 2.
    // The neighbors of i are i-1 and i+1. These neighbors cannot be in indicesToMakePeak,
    // because indicesToMakePeak only contains odd indices (1, 3, 5, ...).
    // i-1 and i+1 are even indices (0-indexed: 0, 2, 4, ...).
    // Since we only modify elements at odd indices, the neighbors' values (currentNums[i-1] and currentNums[i+1])
    // remain at their original values (or values potentially increased if they were chosen as peaks, which they are not).
    // Wait, the neighbors i-1 and i+1 are *not* modified in this loop.
    // The elements in indicesToMakePeak are only increased.
    // The elements at indices i-1 and i+1 are never in indicesToMakePeak.
    // Thus, the requiredMin calculation is correct: it uses the neighbors' values as they are currently in `currentNums`,
    // which are the original `nums` values for neighbors, and the potentially increased value for `currentNums[i]` itself.
    // Since we calculate cost based on the *current* state before applying it, and we apply the cost *to* currentNums[i],
    // and the neighbors are never peaks, this greedy strategy works for this fixed set of indices.

    // Since the set {1, 3, 5, ...} maximizes the count and minimizes the cost for that specific configuration (by prioritizing peaks that need less boost relative to neighbors),
    // and any other set of indices $I'$ of size $k$ would require at least as much or more modification to satisfy the peak conditions compared to this tightly packed configuration, this result is the minimum.
    // In general, for a fixed set of peaks, the minimum cost is achieved by making the peak just large enough. Since the separation ensures the local constraints are independent, the greedy application on the tightly packed set yields the global minimum cost for achieving max count.

    return totalCost;
}

