func solve(nums []int64) int64 {
	n := len(nums)

	// The maximum number of special indices achievable is floor((n - 1) / 2).
	maxSpecialIndices := (n - 1) / 2

	if maxSpecialIndices == 0 {
		return 0
	}

	k := maxSpecialIndices
	indicesToMakePeak := make([]int, k)
	for j := 0; j < k; j++ {
		// We choose the indices 1, 3, 5, ..., 2k-1 (0-indexed)
		indicesToMakePeak[j] = 2*j + 1
	}

	currentNums := make([]int64, n)
	copy(currentNums, nums)
	var totalCost int64 = 0

	// Iterate through the chosen peak indices in increasing order.
	for _, i := range indicesToMakePeak {
		// Target value for nums'[i] must be strictly greater than its current neighbors.
		// Neighbors are i-1 and i+1.
		requiredMin := int64(0)

		// Neighbor i-1
		requiredMin = max(requiredMin, currentNums[i-1]+1)

		// Neighbor i+1
		requiredMin = max(requiredMin, currentNums[i+1]+1)

		// The cost is incurred only if currentNums[i] is less than the required minimum.
		cost := int64(0)
		if requiredMin > currentNums[i] {
			cost = requiredMin - currentNums[i]
		}

		totalCost += cost

		// Update the array for subsequent calculations.
		currentNums[i] += cost
	}

	return totalCost
}

func max(a, b int64) int64 {
	if a > b {
		return a
	}
	return b
}
